import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  it.todo("quote: empty item list → premium 5 G (only processing fee)");

  it.todo("quote: single sword → premium 105 G (100 base + 5 fee)");
  it.todo("quote: single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("quote: single staff → premium 85 G (80 base + 5 fee)");
  it.todo("quote: single potion → premium 45 G (40 base + 5 fee)");
  it.todo("quote: single rune → premium 30 G (25 base + 5 fee)");
  it.todo("quote: single moonstone → premium 30 G (25 base + 5 fee)");

  it.todo("quote: 2 runes → premium 55 G (50 base + 5 fee, no block)");
  it.todo("quote: 3 runes → premium 65 G (60 base + 5 fee, block applies)");
  it.todo("quote: 4 runes → premium 105 G (100 base + 5 fee, no block — block requires exactly 3)");
  it.todo("quote: 7 runes → premium 180 G (175 base + 5 fee: 2 blocks of 3 = 120, 1 leftover = 25)");
  it.todo("quote: 2 runes + 1 moonstone → premium 80 G (75 base + 5 fee, no block: different types)");
  it.todo("quote: 3 runes + 3 moonstones → premium 125 G (120 base + 5 fee, two separate blocks)");

  it.todo("quote: cursed sword → premium 155 G (100 base + 50 curse surcharge + 5 fee)");
  it.todo("quote: sword enchantment 5 → premium 135 G (100 base + 30 high-enchantment surcharge + 5 fee)");
  it.todo("quote: cursed sword enchantment 5 → premium 185 G (100 base + 50 curse + 30 high-ench + 5 fee)");
  it.todo("quote: sword enchantment 4 → premium 105 G (no high-enchantment surcharge)");

  it.todo("quote: loyalty discount at exactly 2 years on sword → premium 85 G (100 base - 20 loyalty + 5 fee)");
  it.todo("quote: first insurance surcharge on sword → premium 115 G (100 base + 10 first-ins + 5 fee)");
  it.todo("quote: follow-up contract (2nd quote) on sword → premium 90 G (100 base - 15 follow-up + 5 fee)");

  it.todo("quote: cursed sword + plain amulet → premium 215 G (160 base + 50 curse on sword only + 5 fee)");

  it.todo("quote: newcomer with cursed sword (0 years, 1st contract) → premium 165 G (100 + 50 curse + 10 first-ins + 5 fee)");
  it.todo("quote: long-standing 2nd contract: 3 years, cursed sword enchantment 7 → premium 160 G (100 + 50 curse + 30 high-ench - 20 loyalty + 10 first-ins - 15 follow-up + 5 fee)");

  it.todo("quote: premium rounding 197.5 → 198 G (rounded up in MHPCO favor)");

  it.todo("claim: regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full - 100 deductible)");
  it.todo("claim: damage to rune, damage 200 G → payout 100 G (full reimbursement - 100 deductible; runes have no enchantment or material)");

  it.todo("claim: dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per item: 500-100 + 300-100 = 600)");

  it.todo("claim: dragon-material sword enchantment 8, damage 1000 G → payout 400 G (high-enchantment 50% = 500, then -100 deductible)");
  it.todo("claim: dragon-material sword enchantment 5, damage 800 G → payout 700 G (dragon material: full, then -100 deductible)");
  it.todo("claim: dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins: 500 - 100 deductible)");
  it.todo("claim: steel sword enchantment 9, damage 1000 G → payout 400 G (only high-enchantment: 50% = 500 - 100 deductible)");

  it.todo("claim: two swords insured → insurance sum 2000 G, cap 4000 G");
  it.todo("claim: dragon attack damages both swords → each is separate damage with own deductible");

  it.todo("claim: sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("claim: cursed sword → cap 2000 G (based on unmodified insurance value, not premium)");
  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 G (block doesn't affect insurance sum)");

  it.todo("claim: sword insured (cap 2000 G); two successive claims of 1500 G each → first payout 1400 G cap 600 G; second payout 600 G cap 0 G");

  it.todo("claim: payout rounding 350.5 → 350 G (rounded down in MHPCO favor)");

  it.todo("error: unknown item type → throws error");
  it.todo("error: damage to item not in policy → throws error");
  it.todo("error: negative damage amount → throws error");
  it.todo("error: more damages of a type than policy covers → throws error");
});

