type Item = { type: string };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function computeBasePremium(items: Item[]): number {
  return items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
}

export function processScenario(input: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items: Item[] }> }): { results: Array<{ premium: number }> } {
  const step = input.steps[0];
  const basePremium = computeBasePremium(step.items);
  return { results: [{ premium: basePremium + 5 }] };
}

input.newString:
type Item = { type: string };

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_PRICE = 60;

function computeBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const [compType, count] of Object.entries(componentCounts)) {
    if (count % 3 === 0) {
      total += (count / 3) * BLOCK_PRICE;
    } else {
      total += count * BASE_PREMIUMS[compType];
    }
  }

  return total;
}

export function processScenario(input: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items: Item[] }> }): { results: Array<{ premium: number }> } {
  const step = input.steps[0];
  const basePremium = computeBasePremium(step.items);
  return { results: [{ premium: basePremium + 5 }] };
}

