type QuoteStep = { op: "quote"; items: Item[] };
type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
type Step = QuoteStep | ClaimStep;

function computePolicyWideModifiers(basePremium: number, yearsWithMHPCO: number, quoteIndex: number): number {
  let modifier = 0;
  if (yearsWithMHPCO >= 2) modifier -= basePremium * 0.2;
  modifier += basePremium * 0.1;
  if (quoteIndex > 0) modifier -= basePremium * 0.15;
  return modifier;
}

export function processScenario(input: { customer: { yearsWithMHPCO: number }; steps: Step[] }): { results: Array<{ premium: number }> } {
  const results: Array<{ premium: number }> = [];
  let quoteCount = 0;

  for (const step of input.steps) {
    if (step.op === "quote") {
      const basePremium = computeBasePremium(step.items);
      const itemSurcharges = computeItemSurcharges(step.items);
      const policyWideModifiers = computePolicyWideModifiers(basePremium, input.customer.yearsWithMHPCO, quoteCount);
      results.push({ premium: Math.ceil(basePremium + itemSurcharges + policyWideModifiers + 5) });
      quoteCount++;
    }
  }

  return { results };
}

